import type { TranscriptEntry } from "./types";

const DEFAULT_MAX_ENTRIES = 5000;

/** Accumulates transcript entries from data channel messages. */
export class TranscriptAccumulator {
  private entries: TranscriptEntry[] = [];
  private maxEntries: number;

  constructor(maxEntries = DEFAULT_MAX_ENTRIES) {
    this.maxEntries = maxEntries;
  }

  /** Add a new transcript entry. Evicts oldest entries if limit is exceeded. */
  add(entry: TranscriptEntry): void {
    this.entries.push(entry);
    if (this.entries.length > this.maxEntries) {
      this.entries = this.entries.slice(-this.maxEntries);
    }
  }

  /** Get all transcript entries (read-only). */
  getAll(): ReadonlyArray<TranscriptEntry> {
    return this.entries;
  }

  /** Clear all transcript entries. */
  clear(): void {
    this.entries = [];
  }
}
