/** Strongly-typed event emitter for VocalBridge events. */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class TypedEventEmitter<EventMap extends Record<string, any>> {
  private listeners = new Map<
    keyof EventMap,
    Set<(data: EventMap[keyof EventMap]) => void>
  >();

  on<K extends keyof EventMap>(
    event: K,
    listener: (data: EventMap[K]) => void,
  ): this {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(listener as (data: EventMap[keyof EventMap]) => void);
    return this;
  }

  off<K extends keyof EventMap>(
    event: K,
    listener: (data: EventMap[K]) => void,
  ): this {
    this.listeners.get(event)?.delete(listener as (data: EventMap[keyof EventMap]) => void);
    return this;
  }

  once<K extends keyof EventMap>(
    event: K,
    listener: (data: EventMap[K]) => void,
  ): this {
    const wrapper = ((data: EventMap[K]) => {
      this.off(event, wrapper);
      listener(data);
    }) as (data: EventMap[K]) => void;
    return this.on(event, wrapper);
  }

  protected emit<K extends keyof EventMap>(event: K, data: EventMap[K]): void {
    const set = this.listeners.get(event);
    if (set) {
      for (const listener of set) {
        try {
          (listener as (data: EventMap[K]) => void)(data);
        } catch {
          // Don't let listener errors crash the emitter
        }
      }
    }
  }

  protected removeAllListeners(): void {
    this.listeners.clear();
  }
}
