import {
  Room,
  RoomEvent,
  Track,
  type RemoteTrack,
  type RemoteTrackPublication,
  type RemoteParticipant,
} from "livekit-client";

/** Manages microphone capture and agent audio playback. */
export class AudioManager {
  private room: Room;
  private autoPlay: boolean;
  private audioElements: Map<string, HTMLAudioElement> = new Map();
  private micEnabled = false;

  constructor(room: Room, options: { autoPlay: boolean }) {
    this.room = room;
    this.autoPlay = options.autoPlay;

    if (this.autoPlay) {
      this.room.on(
        RoomEvent.TrackSubscribed,
        this.handleTrackSubscribed,
      );
      this.room.on(
        RoomEvent.TrackUnsubscribed,
        this.handleTrackUnsubscribed,
      );
    }
  }

  /** Start capturing from microphone and publish to room. */
  async startMicrophone(captureDefaults?: {
    echoCancellation?: boolean;
    noiseSuppression?: boolean;
    autoGainControl?: boolean;
  }): Promise<void> {
    await this.room.localParticipant.setMicrophoneEnabled(true, {
      echoCancellation: captureDefaults?.echoCancellation ?? true,
      noiseSuppression: captureDefaults?.noiseSuppression ?? true,
      autoGainControl: captureDefaults?.autoGainControl ?? true,
    });
    this.micEnabled = true;
  }

  /** Set microphone enabled/disabled. */
  async setEnabled(enabled: boolean): Promise<void> {
    await this.room.localParticipant.setMicrophoneEnabled(enabled);
    this.micEnabled = enabled;
  }

  /** Whether mic is currently enabled. */
  get isEnabled(): boolean {
    return this.micEnabled;
  }

  /** Clean up all audio elements and remove event listeners. */
  dispose(): void {
    for (const [sid, el] of this.audioElements) {
      el.srcObject = null;
      el.remove();
      this.audioElements.delete(sid);
    }

    if (this.autoPlay) {
      this.room.off(
        RoomEvent.TrackSubscribed,
        this.handleTrackSubscribed,
      );
      this.room.off(
        RoomEvent.TrackUnsubscribed,
        this.handleTrackUnsubscribed,
      );
    }
  }

  private handleTrackSubscribed = (
    track: RemoteTrack,
    publication: RemoteTrackPublication,
    participant: RemoteParticipant,
  ): void => {
    if (track.kind === Track.Kind.Audio) {
      const audioElement = track.attach();
      audioElement.style.display = "none";
      document.body.appendChild(audioElement);
      this.audioElements.set(track.sid!, audioElement);
    }
  };

  private handleTrackUnsubscribed = (
    track: RemoteTrack,
  ): void => {
    if (track.kind === Track.Kind.Audio && track.sid) {
      const el = this.audioElements.get(track.sid);
      if (el) {
        el.srcObject = null;
        el.remove();
        this.audioElements.delete(track.sid);
      }
      // Also detach any elements the runtime may have created
      track.detach().forEach((el) => el.remove());
    }
  };
}
