import {
  Room,
  RoomEvent,
  Track,
  type RemoteParticipant,
  type RemoteTrack,
  type RemoteTrackPublication,
} from "livekit-client";

import type {
  VocalBridgeOptions,
  VocalBridgeEventMap,
  TokenResponse,
  TranscriptEntry,
  ConnectionState as ConnectionStateType,
} from "./types";
import { ConnectionState } from "./types";
import { VocalBridgeError, VocalBridgeErrorCode } from "./errors";
import { TypedEventEmitter } from "./events";
import { createTokenFetcher } from "./auth";
import { AudioManager } from "./audio";
import { TranscriptAccumulator } from "./transcript";
import { encodeAction, decodeMessage } from "./data-channel";
import { DATA_CHANNEL_TOPIC, PROTOCOL_ACTIONS } from "./constants";

export class VocalBridge extends TypedEventEmitter<VocalBridgeEventMap> {
  private options: Required<
    Pick<
      VocalBridgeOptions,
      | "participantName"
      | "autoAckHeartbeat"
      | "autoPlayAudio"
      | "maxReconnectAttempts"
      | "reconnectDelay"
      | "debug"
    >
  > &
    VocalBridgeOptions;
  private fetchToken: () => Promise<TokenResponse>;
  private _room: Room | null = null;
  private audioManager: AudioManager | null = null;
  private transcriptAccumulator = new TranscriptAccumulator();
  private _state: ConnectionStateType = ConnectionState.Disconnected;
  private _agentMode: string | undefined;
  private _roomName: string | undefined;
  private _participantIdentity: string | undefined;
  private _isMicrophoneEnabled = false;
  private reconnectAttempts = 0;
  private _pendingOperation: Promise<void> | null = null;
  private aiAgentQueryHandler:
    | ((query: string) => Promise<string>)
    | null = null;

  constructor(options: VocalBridgeOptions) {
    super();

    this.options = {
      participantName: "User",
      autoAckHeartbeat: true,
      autoPlayAudio: true,
      maxReconnectAttempts: 3,
      reconnectDelay: 2000,
      debug: false,
      ...options,
    };

    this.fetchToken = createTokenFetcher(
      this.options.auth,
      this.options.participantName,
      this.options.sessionId,
    );
  }

  // ---- Lifecycle ----

  /** Connect to the voice agent. Fetches token, establishes connection, publishes mic. */
  async connect(): Promise<void> {
    if (this._pendingOperation) {
      await this._pendingOperation;
    }
    if (
      this._state !== ConnectionState.Disconnected &&
      this._state !== ConnectionState.Reconnecting
    ) {
      this.log("Already connected or connecting");
      return;
    }

    const op = this._connect();
    this._pendingOperation = op;
    try {
      await op;
    } finally {
      if (this._pendingOperation === op) {
        this._pendingOperation = null;
      }
    }
  }

  private async _connect(): Promise<void> {
    this.setState(ConnectionState.Connecting);

    try {
      // 1. Fetch token
      this.log("Fetching token...");
      const tokenResponse = await this.fetchToken();
      this._agentMode = tokenResponse.agent_mode;
      this._roomName = tokenResponse.room_name;
      this._participantIdentity = tokenResponse.participant_identity;

      // 2. Create room
      this._room = new Room({
        adaptiveStream: true,
        dynacast: true,
        audioCaptureDefaults: {
          echoCancellation:
            this.options.audioCaptureDefaults?.echoCancellation ?? true,
          noiseSuppression:
            this.options.audioCaptureDefaults?.noiseSuppression ?? true,
          autoGainControl:
            this.options.audioCaptureDefaults?.autoGainControl ?? true,
        },
      });

      // 3. Set up event handlers
      this.setupRoomListeners(this._room);

      // 4. Create audio manager
      this.audioManager = new AudioManager(this._room, {
        autoPlay: this.options.autoPlayAudio,
      });

      // 5. Connect to voice server
      this.log("Connecting...");
      const connectionUrl = tokenResponse.url || tokenResponse.livekit_url;
      if (!connectionUrl) {
        throw new VocalBridgeError(
          "Token response missing connection URL",
          VocalBridgeErrorCode.TokenFetchFailed,
        );
      }
      await this._room.connect(connectionUrl, tokenResponse.token);

      this.setState(ConnectionState.WaitingForAgent);

      // Check if agent is already present
      for (const participant of this._room.remoteParticipants.values()) {
        if (this.isAgentParticipant(participant)) {
          this.setState(ConnectionState.Connected);
          break;
        }
      }

      // 6. Publish microphone
      this.log("Starting microphone...");
      await this.audioManager.startMicrophone(
        this.options.audioCaptureDefaults,
      );
      this._isMicrophoneEnabled = true;
      this.emit("microphoneChanged", true);

      this.reconnectAttempts = 0;
      this.log("Connected successfully");
    } catch (err) {
      this.setState(ConnectionState.Disconnected);
      const error =
        err instanceof VocalBridgeError
          ? err
          : new VocalBridgeError(
              "Connection failed",
              VocalBridgeErrorCode.ConnectionFailed,
              err,
            );
      this.emit("error", error);
      throw error;
    }
  }

  /** Disconnect from the voice agent. Cleans up all resources. */
  async disconnect(): Promise<void> {
    if (this._pendingOperation) {
      await this._pendingOperation;
    }
    if (this._state === ConnectionState.Disconnected) return;

    const op = this._disconnect();
    this._pendingOperation = op;
    try {
      await op;
    } finally {
      if (this._pendingOperation === op) {
        this._pendingOperation = null;
      }
    }
  }

  private async _disconnect(): Promise<void> {
    this.setState(ConnectionState.Disconnecting);

    try {
      this.audioManager?.dispose();
      this.audioManager = null;

      if (this._room) {
        await this._room.disconnect();
        this._room = null;
      }
    } finally {
      this._isMicrophoneEnabled = false;
      this.setState(ConnectionState.Disconnected);
    }
  }

  // ---- Audio Controls ----

  /** Mute or unmute the microphone. */
  async setMicrophoneEnabled(enabled: boolean): Promise<void> {
    if (!this.audioManager) {
      throw new VocalBridgeError(
        "Not connected",
        VocalBridgeErrorCode.ConnectionFailed,
      );
    }
    await this.audioManager.setEnabled(enabled);
    this._isMicrophoneEnabled = enabled;
    this.emit("microphoneChanged", enabled);
  }

  /** Toggle microphone mute state. */
  async toggleMicrophone(): Promise<void> {
    await this.setMicrophoneEnabled(!this._isMicrophoneEnabled);
  }

  // ---- Client Actions ----

  /** Send a custom action to the agent via the data channel. */
  async sendAction(
    action: string,
    payload: Record<string, unknown> = {},
  ): Promise<void> {
    if (!this._room?.localParticipant) {
      throw new VocalBridgeError(
        "Not connected — cannot send action",
        VocalBridgeErrorCode.DataChannelError,
      );
    }

    const data = encodeAction(action, payload);
    await this._room.localParticipant.publishData(data, {
      reliable: true,
      topic: DATA_CHANNEL_TOPIC,
    });
  }

  /** Send a response to an AI agent query. */
  async sendAIAgentResponse(
    turnId: string,
    response: string,
  ): Promise<void> {
    await this.sendAction(PROTOCOL_ACTIONS.AGENT_RESPONSE, {
      response: response.slice(0, 50_000),
      turn_id: turnId,
    });
  }

  // ---- AI Agent Query Handler ----

  /**
   * Register a handler for AI Agent queries.
   * The return value is automatically sent back as agent_response.
   * Returns an unsubscribe function.
   */
  onAIAgentQuery(
    handler: (query: string) => Promise<string>,
  ): () => void {
    this.aiAgentQueryHandler = handler;
    return () => {
      if (this.aiAgentQueryHandler === handler) {
        this.aiAgentQueryHandler = null;
      }
    };
  }

  // ---- Read-only State ----

  /** Current connection state. */
  get state(): ConnectionStateType {
    return this._state;
  }

  /** Whether the microphone is enabled. */
  get isMicrophoneEnabled(): boolean {
    return this._isMicrophoneEnabled;
  }

  /** Accumulated transcript entries. */
  get transcript(): ReadonlyArray<TranscriptEntry> {
    return this.transcriptAccumulator.getAll();
  }

  /** Clear all accumulated transcript entries. */
  clearTranscript(): void {
    this.transcriptAccumulator.clear();
  }

  /** Agent mode from the token response. */
  get agentMode(): string | undefined {
    return this._agentMode;
  }

  /** Room name from the current session. */
  get roomName(): string | undefined {
    return this._roomName;
  }

  /** Participant identity from the current session. */
  get participantIdentity(): string | undefined {
    return this._participantIdentity;
  }

  /**
   * Access the underlying Room for advanced use cases.
   * Using this directly bypasses SDK validation and size limits.
   */
  get room(): Room | null {
    return this._room;
  }

  // ---- Private ----

  private setState(state: ConnectionStateType): void {
    if (this._state === state) return;
    this._state = state;
    this.log(`State: ${state}`);
    this.emit("connectionStateChanged", state);
  }

  private setupRoomListeners(room: Room): void {
    room.on(
      RoomEvent.ParticipantConnected,
      (participant: RemoteParticipant) => {
        this.log(`Participant connected: ${participant.identity}`);
        if (
          this._state === ConnectionState.WaitingForAgent &&
          this.isAgentParticipant(participant)
        ) {
          this.setState(ConnectionState.Connected);
        }
      },
    );

    room.on(
      RoomEvent.TrackSubscribed,
      (
        track: RemoteTrack,
        publication: RemoteTrackPublication,
        participant: RemoteParticipant,
      ) => {
        // If we get an audio track and are still waiting, transition to connected
        if (
          track.kind === Track.Kind.Audio &&
          this._state === ConnectionState.WaitingForAgent
        ) {
          this.setState(ConnectionState.Connected);
        }
      },
    );

    room.on(RoomEvent.Disconnected, () => {
      this.log("Room disconnected");
      if (this._state !== ConnectionState.Disconnecting) {
        this.handleUnexpectedDisconnect();
      }
    });

    room.on(RoomEvent.DataReceived, (
      payload: Uint8Array,
      participant?: RemoteParticipant,
      kind?: unknown,
      topic?: string,
    ) => {
      if (topic === DATA_CHANNEL_TOPIC) {
        this.handleDataChannelMessage(payload);
      }
    });

    room.on(RoomEvent.MediaDevicesError, (error?: Error) => {
      this.emit(
        "error",
        new VocalBridgeError(
          error?.message || "Microphone access denied",
          VocalBridgeErrorCode.MicrophoneError,
          error,
        ),
      );
    });
  }

  private handleDataChannelMessage(payload: Uint8Array): void {
    const message = decodeMessage(payload);
    if (!message) return;

    switch (message.action) {
      case PROTOCOL_ACTIONS.HEARTBEAT: {
        const heartbeat = {
          timestamp:
            typeof message.payload.timestamp === "number"
              ? message.payload.timestamp
              : Date.now(),
          agent_identity:
            typeof message.payload.agent_identity === "string"
              ? message.payload.agent_identity
              : "unknown",
        };
        this.emit("heartbeat", heartbeat);

        if (this.options.autoAckHeartbeat) {
          this.sendAction(PROTOCOL_ACTIONS.HEARTBEAT_ACK, {
            timestamp: heartbeat.timestamp,
          }).catch(() => {
            // Best-effort ack
          });
        }
        break;
      }

      case PROTOCOL_ACTIONS.SEND_TRANSCRIPT: {
        const { role, text, timestamp } = message.payload;
        if (
          (role !== "user" && role !== "agent") ||
          typeof text !== "string"
        ) {
          break; // Malformed transcript entry — ignore
        }
        const entry: TranscriptEntry = {
          role,
          text: text.slice(0, 50_000), // Cap at 50KB to prevent memory abuse
          timestamp: typeof timestamp === "number" ? timestamp : Date.now(),
        };
        this.transcriptAccumulator.add(entry);
        this.emit("transcript", entry);
        break;
      }

      case PROTOCOL_ACTIONS.QUERY_AGENT: {
        const rawQuery = message.payload.query;
        const turnId = message.payload.turn_id;
        if (typeof rawQuery !== "string" || typeof turnId !== "string") {
          break; // Malformed query — ignore
        }
        const query = rawQuery.slice(0, 50_000);

        // If a callback handler is registered, use it (auto-respond)
        if (this.aiAgentQueryHandler) {
          this.aiAgentQueryHandler(query)
            .then((response) => {
              return this.sendAIAgentResponse(turnId, response);
            })
            .catch((err) => {
              this.emit(
                "error",
                new VocalBridgeError(
                  "AI Agent query handler failed",
                  VocalBridgeErrorCode.DataChannelError,
                  err,
                ),
              );
            });
        }

        // Always emit the event (for event-based usage)
        this.emit("aiAgentQuery", { query, turnId });
        break;
      }

      case PROTOCOL_ACTIONS.HEARTBEAT_ACK:
      case PROTOCOL_ACTIONS.AGENT_RESPONSE:
        // Ignore outbound protocol messages echoed back
        break;

      default:
        // Custom agent action
        this.emit("agentAction", {
          action: message.action,
          payload: message.payload,
        });
        break;
    }
  }

  private isAgentParticipant(participant: RemoteParticipant): boolean {
    // Only non-local participants that are not this client are agent candidates.
    // The server designates agent participants with metadata or a known identity prefix.
    const id = participant.identity;
    return (
      id !== this._participantIdentity &&
      (id.startsWith("agent-") || id.startsWith("vb-agent-"))
    );
  }

  private async handleUnexpectedDisconnect(): Promise<void> {
    if (this.reconnectAttempts >= this.options.maxReconnectAttempts) {
      this.audioManager?.dispose();
      this.audioManager = null;
      this._room = null;
      this._isMicrophoneEnabled = false;
      this.setState(ConnectionState.Disconnected);
      this.emit(
        "error",
        new VocalBridgeError(
          "Reconnection failed after max attempts",
          VocalBridgeErrorCode.ReconnectFailed,
        ),
      );
      return;
    }

    this.setState(ConnectionState.Reconnecting);
    this.reconnectAttempts++;
    this.log(
      `Reconnecting (attempt ${this.reconnectAttempts}/${this.options.maxReconnectAttempts})...`,
    );

    // Clean up old resources
    this.audioManager?.dispose();
    this.audioManager = null;
    this._room = null;

    await new Promise((resolve) =>
      setTimeout(resolve, this.options.reconnectDelay),
    );

    try {
      await this.connect();
    } catch {
      // connect() already handles errors and state transitions
    }
  }

  private log(message: string): void {
    if (this.options.debug) {
      console.log(`[VocalBridge] ${message}`);
    }
  }
}
